import React, { useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import { loadStripe } from '@stripe/stripe-js';
import { Elements, CardElement, useStripe, useElements } from '@stripe/react-stripe-js';
import './App.css';

const stripePromise = loadStripe(process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY || 'pk_test_51Na0i5J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0J0');

const roles = [
  'Super Admin', 'Principal', 'Vice Principal', 'Admin', 'Teacher', 'Student', 'Parent', 'Accountant'
];

const roleOptions = {
  'Super Admin': [
    { label: 'Create Schools', action: 'renderCreateSchools' },
    { label: 'Create Principals', action: 'renderCreatePrincipals' },
    { label: 'Create Admins', action: 'renderCreateAdmins' },
    { label: 'Manage Subscriptions', action: 'renderManageSubscriptions' },
    { label: 'View Total Students', action: 'renderViewTotalStudents' },
    { label: 'View Total Teachers', action: 'renderViewTotalTeachers' },
    { label: 'View Revenue Reports', action: 'renderViewRevenueReports' },
    { label: 'System Settings', action: 'renderSystemSettings' },
    { label: 'Backup & Restore', action: 'renderBackupRestore' },
    { label: 'Audit Logs', action: 'renderAuditLogs' }
  ],
  'Principal': [
    { label: 'Approve Admissions', action: 'renderApproveAdmissions' },
    { label: 'Manage Teachers', action: 'renderManageTeachers' },
    { label: 'Manage Classes', action: 'renderManageClasses' },
    { label: 'Assign Class Teachers', action: 'renderAssignClassTeachers' },
    { label: 'Generate Reports', action: 'renderGenerateReports' },
    { label: 'Send Announcements', action: 'renderSendAnnouncements' },
    { label: 'Approve Leave Requests', action: 'renderApproveLeaveRequests' }
  ],
  'Vice Principal': [
    { label: 'Monitor Attendance', action: 'renderMonitorAttendance' },
    { label: 'Check Teacher Performance', action: 'renderCheckTeacherPerformance' },
    { label: 'Handle Discipline Cases', action: 'renderHandleDisciplineCases' },
    { label: 'Schedule Exams', action: 'renderScheduleExams' },
    { label: 'Review Academic Reports', action: 'renderReviewAcademicReports' }
  ],
  'Admin': [
    { label: 'Student Records', action: 'renderStudentRecords' },
    { label: 'Staff Records', action: 'renderStaffRecords' },
    { label: 'Register Students', action: 'renderRegisterStudents' },
    { label: 'Register Teachers', action: 'renderRegisterTeachers' },
    { label: 'Transport Management', action: 'renderTransportManagement' },
    { label: 'Hostel Management', action: 'renderHostelManagement' },
    { label: 'Inventory Management', action: 'renderInventoryManagement' },
    { label: 'Certificate Generation', action: 'renderCertificateGeneration' }
  ],
  'Teacher': [
    { label: 'Mark Attendance', action: 'renderMarkAttendance' },
    { label: 'Enter Marks', action: 'renderEnterMarks' },
    { label: 'Upload Assignments', action: 'renderUploadAssignments' },
    { label: 'Create Exams', action: 'renderCreateExams' },
    { label: 'Communicate with Parents', action: 'renderCommunicateWithParents' },
    { label: 'Track Student Progress', action: 'renderTrackStudentProgress' }
  ],
  'Student': [
    { label: 'View Attendance', action: 'renderViewStudentAttendance' },
    { label: 'View Marks', action: 'renderViewStudentMarks' },
    { label: 'View Timetable', action: 'renderViewStudentTimetable' },
    { label: 'Download Study Materials', action: 'renderDownloadMaterials' },
    { label: 'Submit Assignments', action: 'renderSubmitAssignments' },
    { label: 'Pay Fees', action: 'renderPayStudentFees' },
    { label: 'View Notifications', action: 'renderViewStudentNotifications' }
  ],
  'Parent': [
    { label: 'Monitor Child Progress', action: 'renderMonitorChildProgress' },
    { label: 'View Attendance', action: 'renderViewChildAttendance' },
    { label: 'Pay Fees', action: 'renderPayChildFees' },
    { label: 'Chat with Teachers', action: 'renderChatWithTeachers' },
    { label: 'Download Report Cards', action: 'renderDownloadReportCards' }
  ],
  'Accountant': [
    { label: 'Fee Collection', action: 'renderFeeCollection' },
    { label: 'Salary Management', action: 'renderSalaryManagement' },
    { label: 'Expense Tracking', action: 'renderExpenseTracking' },
    { label: 'Financial Reports', action: 'renderFinancialReports' },
    { label: 'Tax Reports', action: 'renderTaxReports' }
  ]
};

const getPanelHeroImage = (title) => {
  if (/school|school profile|principal|admin/i.test(title)) {
    return 'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?auto=format&fit=crop&w=800&q=80';
  }
  if (/student|attendance|marks|report|timetable|assignments|homework/i.test(title)) {
    return 'https://images.unsplash.com/photo-1523240795612-9a054b0db644?auto=format&fit=crop&w=800&q=80';
  }
  if (/teacher|class|performance|discipline|exams|communicate/i.test(title)) {
    return 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&w=800&q=80';
  }
  if (/finance|expense|salary|fee|tax/i.test(title)) {
    return 'https://images.unsplash.com/photo-1522075469751-3a6694fb2f61?auto=format&fit=crop&w=800&q=80';
  }
  return 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&w=800&q=80';
};

const initialState = {
  schools: [
    { id: 'SCH100', name: 'Cedar Valley High School', location: 'Sector 22', board: 'CBSE', licenseKey: 'LIC-9842', status: 'Active', tier: 'Enterprise' },
    { id: 'SCH101', name: 'Sunrise Academy', location: 'Downtown', board: 'ICSE', licenseKey: 'LIC-1033', status: 'Suspended', tier: 'Premium' }
  ],
  students: [
    { admissionNumber: 'STD001', name: 'Aarav Singh', grade: '5', section: 'A', parent: { name: 'Pooja Singh', contact: '9876543210' }, attendance: { present: 152, absent: 8, late: 2 }, marks: { Math: 88, Science: 92, English: 85 }, status: 'Active' },
    { admissionNumber: 'STD002', name: 'Meera Sharma', grade: '6', section: 'B', parent: { name: 'Suresh Sharma', contact: '9876512340' }, attendance: { present: 148, absent: 12, late: 1 }, marks: { Math: 92, Science: 89, English: 90 }, status: 'Active' },
    { admissionNumber: 'STD003', name: 'Riya Patel', grade: '4', section: 'C', parent: { name: 'Nilesh Patel', contact: '9876501234' }, attendance: { present: 160, absent: 4, late: 0 }, marks: { Math: 95, Science: 94, English: 91 }, status: 'Active' }
  ],
  teachers: [
    { employeeId: 'TCH100', name: 'Priya Nair', subjects: ['Mathematics', 'Physics'], salary: 62000, leaveStatus: 'Pending', assignedClasses: ['5A', '6B'] },
    { employeeId: 'TCH101', name: 'Rahul Kapur', subjects: ['English', 'History'], salary: 58000, leaveStatus: 'Approved', assignedClasses: ['4C'] },
    { employeeId: 'TCH102', name: 'Sneha Rao', subjects: ['Biology', 'Chemistry'], salary: 65000, leaveStatus: 'None', assignedClasses: ['6B', '5A'] }
  ],
  principals: [],
  admins: [],
  financials: {
    fees: [
      { id: 'FEE001', student: 'Aarav Singh', grade: '5', type: 'Tuition', amount: 45000, dueDate: '2026-07-05', status: 'Pending' },
      { id: 'FEE002', student: 'Meera Sharma', grade: '6', type: 'Transport', amount: 12000, dueDate: '2026-07-15', status: 'Paid' },
      { id: 'FEE003', student: 'Riya Patel', grade: '4', type: 'Hostel', amount: 55000, dueDate: '2026-08-01', status: 'Pending' }
    ],
    expenses: [
      { id: 'EXP100', category: 'Utilities', description: 'Electricity bill for June', amount: 22000, date: '2026-06-10' },
      { id: 'EXP101', category: 'Maintenance', description: 'Lift servicing', amount: 12500, date: '2026-06-12' }
    ]
  },
  notifications: [
    { id: 1, message: '[Teacher uploaded homework] Homework posted for Grade 5.', channels: ['Student', 'Parent'], time: '09:02 AM' },
    { id: 2, message: '[Fee payment successful] Aarav Singh fee cleared.', channels: ['Accountant', 'Parent'], time: '08:50 AM' },
    { id: 3, message: '[Principal approved admission] New student batch admitted.', channels: ['Admin', 'Parent', 'Accountant'], time: '08:15 AM' }
  ],
  auditLogs: [
    { id: 'AL001', action: 'Created new school profile', user: 'Super Admin', time: '07:45 AM', ip: '192.168.1.11' },
    { id: 'AL002', action: 'Approved admission request', user: 'Principal', time: '08:15 AM', ip: '192.168.1.22' }
  ],
  pendingAdmissions: [
    { admissionNumber: 'PEN100', name: 'Kabir Jain', grade: '5', section: 'A', parent: 'Rashmi Jain' },
    { admissionNumber: 'PEN101', name: 'Neha Verma', grade: '6', section: 'B', parent: 'Kiran Verma' }
  ],
  leaveRequests: [
    { id: 'LR100', teacher: 'Priya Nair', date: '2026-06-18', reason: 'Medical appointment', status: 'Pending' },
    { id: 'LR101', teacher: 'Rahul Kapur', date: '2026-06-20', reason: 'Personal work', status: 'Pending' }
  ],
  assignments: [
    { id: 'ASG100', title: 'Algebra practice', subject: 'Mathematics', deadline: '2026-06-28', createdBy: 'Priya Nair' }
  ],
  announcements: [],
  messages: []
};

function App() {
  const [state, setState] = useState(initialState);
  const [currentRole, setCurrentRole] = useState('Super Admin');
  const [activeAction, setActiveAction] = useState(roleOptions['Super Admin'][0].action);
  const [user, setUser] = useState(null);
  const [authError, setAuthError] = useState('');

  useEffect(() => {
    if (!user) return;
    const fetchData = async () => {
      try {
        const [schoolsRes, studentsRes, teachersRes] = await Promise.all([
          axios.get('/api/schools'),
          axios.get('/api/students'),
          axios.get('/api/teachers')
        ]);
        setState(prev => ({
          ...prev,
          schools: schoolsRes.data.length ? schoolsRes.data : prev.schools,
          students: studentsRes.data.length ? studentsRes.data : prev.students,
          teachers: teachersRes.data.length ? teachersRes.data : prev.teachers
        }));
      } catch (error) {
        console.error('Failed to load backend data:', error);
      }
    };
    fetchData();
  }, [user]);

  const selectedStudents = useMemo(() => state.students.filter(student => student.grade === '5'), [state.students]);

  const handleLogin = async (event) => {
    event.preventDefault();
    setAuthError('');
    const form = event.target;
    const email = form.loginEmail.value;
    const password = form.loginPassword.value;

    try {
      const response = await axios.post('/api/auth/login', { email, password });
      const token = response.data.token;
      setUser({ email, role: response.data.role, userId: response.data.userId, token });
      axios.defaults.headers.common.Authorization = `Bearer ${token}`;
      setCurrentRole(response.data.role);
      setActiveAction(roleOptions[response.data.role]?.[0]?.action || 'renderStudentRecords');
      form.reset();
    } catch (err) {
      console.error('Login failed', err);
      setAuthError(err.response?.data?.error || 'Login failed.');
    }
  };

  const handleSignUp = async (event) => {
    event.preventDefault();
    setAuthError('');
    const form = event.target;
    const email = form.signupEmail.value;
    const password = form.signupPassword.value;
    const role = form.signupRole.value;

    try {
      const response = await axios.post('/api/auth/register', { email, password, role });
      const token = response.data.token;
      setUser({ email, role, userId: response.data.userId, token });
      axios.defaults.headers.common.Authorization = `Bearer ${token}`;
      setCurrentRole(role);
      setActiveAction(roleOptions[role]?.[0]?.action || 'renderStudentRecords');
      form.reset();
    } catch (err) {
      console.error('Sign up failed', err);
      setAuthError(err.response?.data?.error || 'Sign up failed.');
    }
  };

  const handleLogout = () => {
    setUser(null);
    delete axios.defaults.headers.common.Authorization;
    setAuthError('');
    setCurrentRole('Super Admin');
    setActiveAction(roleOptions['Super Admin'][0].action);
  };

  const renderWorkspace = () => {
    switch (activeAction) {
      case 'renderCreateSchools':
        return <CreateSchools state={state} setState={setState} />;
      case 'renderCreatePrincipals':
        return <CreatePrincipals state={state} setState={setState} />;
      case 'renderCreateAdmins':
        return <CreateAdmins state={state} setState={setState} />;
      case 'renderRegisterStudents':
        return <RegisterStudents state={state} setState={setState} />;
      case 'renderRegisterTeachers':
        return <RegisterTeachers state={state} setState={setState} />;
      case 'renderManageSubscriptions':
        return <ManageSubscriptions state={state} setState={setState} />;
      case 'renderViewTotalStudents':
        return <ViewTotalStudents state={state} />;
      case 'renderViewTotalTeachers':
        return <ViewTotalTeachers state={state} />;
      case 'renderViewRevenueReports':
        return <ViewRevenueReports state={state} />;
      case 'renderSystemSettings':
        return <SystemSettings setState={setState} />;
      case 'renderBackupRestore':
        return <BackupRestore state={state} setState={setState} />;
      case 'renderAuditLogs':
        return <AuditLogs state={state} />;
      case 'renderApproveAdmissions':
        return <ApproveAdmissions state={state} setState={setState} />;
      case 'renderManageTeachers':
        return <ManageTeachers state={state} setState={setState} />;
      case 'renderManageClasses':
        return <ManageClasses />;
      case 'renderAssignClassTeachers':
        return <AssignClassTeachers state={state} setState={setState} />;
      case 'renderGenerateReports':
        return <GenerateReports state={state} setState={setState} />;
      case 'renderSendAnnouncements':
        return <SendAnnouncements state={state} setState={setState} />;
      case 'renderApproveLeaveRequests':
        return <ApproveLeaveRequests state={state} setState={setState} />;
      case 'renderMonitorAttendance':
        return <MonitorAttendance />;
      case 'renderCheckTeacherPerformance':
        return <CheckTeacherPerformance state={state} />;
      case 'renderHandleDisciplineCases':
        return <HandleDisciplineCases />;
      case 'renderScheduleExams':
        return <ScheduleExams state={state} setState={setState} />;
      case 'renderReviewAcademicReports':
        return <ReviewAcademicReports state={state} />;
      case 'renderStudentRecords':
        return <StudentRecords state={state} />;
      case 'renderStaffRecords':
        return <StaffRecords state={state} />;
      case 'renderTransportManagement':
        return <TransportManagement />;
      case 'renderHostelManagement':
        return <HostelManagement />;
      case 'renderInventoryManagement':
        return <InventoryManagement />;
      case 'renderCertificateGeneration':
        return <CertificateGeneration state={state} />;
      case 'renderMarkAttendance':
        return <MarkAttendance state={state} setState={setState} />;
      case 'renderEnterMarks':
        return <EnterMarks state={state} setState={setState} />;
      case 'renderUploadAssignments':
        return <UploadAssignments state={state} setState={setState} />;
      case 'renderCreateExams':
        return <CreateExams state={state} setState={setState} />;
      case 'renderCommunicateWithParents':
        return <CommunicateWithParents state={state} setState={setState} />;
      case 'renderTrackStudentProgress':
        return <TrackStudentProgress state={state} />;
      case 'renderViewStudentAttendance':
        return <ViewStudentAttendance state={state} />;
      case 'renderViewStudentMarks':
        return <ViewStudentMarks state={state} />;
      case 'renderViewStudentTimetable':
        return <ViewStudentTimetable />;
      case 'renderDownloadMaterials':
        return <DownloadMaterials />;
      case 'renderSubmitAssignments':
        return <SubmitAssignments setState={setState} />;
      case 'renderPayStudentFees':
        return user?.role === 'Student' ? <PayStudentFees state={state} setState={setState} user={user} /> : <ProtectedRouteNotice role="Student" />;
      case 'renderViewStudentNotifications':
        return <ViewStudentNotifications state={state} />;
      case 'renderMonitorChildProgress':
        return <MonitorChildProgress state={state} />;
      case 'renderViewChildAttendance':
        return <ViewChildAttendance state={state} />;
      case 'renderPayChildFees':
        return user?.role === 'Parent' ? <PayChildFees state={state} setState={setState} user={user} /> : <ProtectedRouteNotice role="Parent" />;
      case 'renderChatWithTeachers':
        return <ChatWithTeachers state={state} />;
      case 'renderDownloadReportCards':
        return <DownloadReportCards state={state} />;
      case 'renderFeeCollection':
        return <FeeCollection state={state} setState={setState} />;
      case 'renderSalaryManagement':
        return <SalaryManagement state={state} />;
      case 'renderExpenseTracking':
        return <ExpenseTracking state={state} setState={setState} />;
      case 'renderFinancialReports':
        return <FinancialReports state={state} />;
      case 'renderTaxReports':
        return <TaxReports state={state} />;
      default:
        return <div className="rounded-3xl bg-white p-8 shadow-sm border border-slate-200">Select an option from the sidebar.</div>;
    }
  };

  if (!user) {
    return (
      <div className="app-shell login-shell">
        <header className="topbar">
          <div>
            <h1>School Management Login</h1>
            <p>Use separate credentials for each dashboard role.</p>
          </div>
        </header>
        <main className="workspace">
          <div className="panel-card login-panel">
            <div className="login-hero">
              <div>
                <h2>Welcome to Your School Dashboard</h2>
                <p>Sign in or create an account to open your role-based dashboard with elegant analytics, student management, and reports.</p>
              </div>
              <div className="login-hero-image" />
            </div>
            <div className="panel-header"><div><h2>Login</h2><p>Sign in with role-based dashboard credentials.</p></div></div>
            <form className="grid-form" onSubmit={handleLogin}>
              <label>Email<input name="loginEmail" type="email" required placeholder="user@school.edu" /></label>
              <label>Password<input name="loginPassword" type="password" required placeholder="Your password" /></label>
              <div className="form-actions"><button type="submit">Login</button></div>
            </form>
            <div className="divider">Or create a new dashboard account</div>
            <form className="grid-form" onSubmit={handleSignUp}>
              <label>Email<input name="signupEmail" type="email" required placeholder="newuser@school.edu" /></label>
              <label>Password<input name="signupPassword" type="password" required placeholder="Choose a password" /></label>
              <label>Role<select name="signupRole">{roles.map(role => <option key={role} value={role}>{role}</option>)}</select></label>
              <div className="form-actions"><button type="submit">Create Account</button></div>
            </form>
            {authError && <div className="error-text">{authError}</div>}
          </div>
        </main>
      </div>
    );
  }

  return (
    <Elements stripe={stripePromise}>
      <div className="app-shell">
        <header className="topbar">
          <div>
            <h1>School Management System</h1>
            <p>Modern functional SPA scaffold for MERN development.</p>
          </div>
          <div className="topbar-controls">
            <div className="user-badge">Signed in as {user.email} ({user.role})</div>
            <div className="role-label">Current dashboard: {currentRole}</div>
            <button className="secondary-button" onClick={handleLogout}>Logout</button>
            <div className="notification-badge">{state.notifications.length}</div>
          </div>
        </header>
      <div className="main-grid">
        <aside className="sidebar">
          <div className="sidebar-title">{currentRole} Options</div>
          <div className="sidebar-actions">
            {roleOptions[currentRole].map(option => (
              <button
                key={option.action}
                className={option.action === activeAction ? 'active' : ''}
                onClick={() => setActiveAction(option.action)}
              >
                {option.label}
              </button>
            ))}
          </div>
        </aside>
        <main className="workspace">
          {renderWorkspace()}
        </main>
        <aside className="notifications-panel">
          <div className="panel-header">
            <div>Real-Time Notifications</div>
            <button onClick={() => setState(prev => ({ ...prev, notifications: [] }))}>Clear</button>
          </div>
          <div className="notifications-list">
            {state.notifications.length === 0 ? (
              <div className="empty-state">No notifications yet.</div>
            ) : state.notifications.map(item => (
              <div key={item.id} className="notification-card">
                <div>{item.message}</div>
                <div className="notification-meta">Channels: {item.channels.join(', ')}</div>
                <div className="notification-time">{item.time}</div>
              </div>
            ))}
          </div>
        </aside>
      </div>
    </div>
    </Elements>
  );
}

function panelWrapper(title, description, children) {
  return (
    <div className="panel-card">
      <div className="panel-hero">
        <div className="panel-hero-copy">
          <h2>{title}</h2>
          <p>{description}</p>
        </div>
        <div className="panel-hero-image" style={{ backgroundImage: `linear-gradient(180deg, rgba(15, 23, 42, 0.24), rgba(15, 23, 42, 0.04)), url(${getPanelHeroImage(title)})` }} />
      </div>
      {children}
    </div>
  );
}

function ProtectedRouteNotice({ role }) {
  return panelWrapper('Access Restricted', `Only ${role} users may access this dashboard.`, (
    <div className="empty-state">Please sign in as a {role} to continue.</div>
  ));
}

function CreateSchools({ state, setState }) {
  const handleSubmit = (event) => {
    event.preventDefault();
    const form = event.target;
    const school = {
      id: `SCH${Math.floor(100 + Math.random() * 900)}`,
      name: form.schoolName.value,
      location: form.schoolLocation.value,
      board: form.schoolBoard.value,
      licenseKey: form.schoolLicense.value,
      status: 'Active',
      tier: form.schoolTier.value
    };
    (async () => {
      try {
        const res = await axios.post('/api/schools', school);
        const saved = { ...res.data, id: res.data.id || res.data._id };
        setState(prev => ({ ...prev, schools: [...prev.schools, saved], notifications: [{ id: Date.now(), message: `[Super Admin created school] ${saved.name} enrolled.`, channels: ['Admin', 'Accountant'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications] }));
        form.reset();
      } catch (err) {
        console.error('Create school failed', err);
        alert('Failed to create school (check server).');
      }
    })();
  };

  return panelWrapper('Create Schools', 'Displays a form to input School Name, Location, Board, and License Key.', (
    <form className="grid-form" onSubmit={handleSubmit}>
      <label>
        School Name
        <input name="schoolName" required placeholder="Sunrise Academy" />
      </label>
      <label>
        Location
        <input name="schoolLocation" required placeholder="Downtown" />
      </label>
      <label>
        Board
        <select name="schoolBoard">
          <option>CBSE</option>
          <option>ICSE</option>
          <option>State Board</option>
          <option>IB</option>
        </select>
      </label>
      <label>
        License Key
        <input name="schoolLicense" required placeholder="LIC-1234" />
      </label>
      <label>
        Subscription Tier
        <select name="schoolTier">
          <option>Basic</option>
          <option>Premium</option>
          <option>Enterprise</option>
        </select>
      </label>
      <div className="form-actions"><button type="submit">Add New School</button></div>
    </form>
  ));
}

function CreatePrincipals({ state, setState }) {
  const handleSubmit = (event) => {
    event.preventDefault();
    const form = event.target;
    const principal = {
      id: `PRN${Math.floor(100 + Math.random() * 900)}`,
      name: form.principalName.value,
      email: form.principalEmail.value,
      schoolId: form.principalSchool.value
    };
    (async () => {
      try {
        await axios.post('/api/auth/register', { email: principal.email, password: form.principalKey.value, role: 'Principal' });
        setState(prev => ({ ...prev, principals: [...(prev.principals || []), principal], notifications: [{ id: Date.now(), message: `[Super Admin created principal] ${principal.name} assigned to school ${principal.schoolId}.`, channels: ['Admin'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications] }));
        form.reset();
      } catch (err) {
        console.error('Create principal failed', err);
        alert('Failed to create principal (check server).');
      }
    })();
  };

  return panelWrapper('Create Principals', 'A creation pipeline form to link a master principal login credential to an active registered school.', (
    <form className="grid-form" onSubmit={handleSubmit}>
      <label>
        Principal Name
