function StripeCheckoutForm({ fee, onSuccess, user }) {
  const stripe = useStripe();
  const elements = useElements();
  const [message, setMessage] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (!stripe || !elements) return;
    setMessage('');
    setIsProcessing(true);

    try {
      const intentResponse = await axios.post('/api/payments/create-payment-intent', {
        amount: fee.amount,
        currency: 'usd',
        description: `${fee.type} payment for ${fee.student}`,
        studentEmail: user?.email || 'anonymous@school.edu'
      }, {
        headers: {
          Authorization: `Bearer ${user?.token}`
        }
      });

      const clientSecret = intentResponse.data.clientSecret;
      const cardElement = elements.getElement(CardElement);
      if (!cardElement) throw new Error('Card element not found.');

      const { error, paymentIntent } = await stripe.confirmCardPayment(clientSecret, {
        payment_method: {
          card: cardElement,
          billing_details: {
            email: user?.email,
            name: user?.email
          }
        }
      });

      if (error) {
        setMessage(error.message || 'Payment failed.');
      } else if (paymentIntent?.status === 'succeeded') {
        onSuccess(fee.id);
        setMessage('Payment succeeded. Thank you!');
      } else {
        setMessage('Payment did not complete.');
      }
    } catch (err) {
      console.error('Payment error', err);
      setMessage(err.response?.data?.message || err.message || 'Unable to process payment.');
    }

    setIsProcessing(false);
  };

  return (
    <form className="grid-form" onSubmit={handleSubmit}>
      <label>
        Card details
        <div className="card-element-container"><CardElement options={{ style: { base: { fontSize: '16px', color: '#32325d', '::placeholder': { color: '#a0aec0' } }, invalid: { color: '#fa755a' } } }} /></div>
      </label>
      <div className="form-actions">
        <button type="submit" disabled={!stripe || isProcessing}>{isProcessing ? 'Processing…' : `Pay ₹${fee.amount.toLocaleString()}`}</button>
      </div>
      {message && <div className="info-text">{message}</div>}
    </form>
  );
}

