        <div className="stat-card"><div>Avg Score</div><div>{Math.round(Object.values(student.marks).reduce((sum, score) => sum + score, 0) / Object.values(student.marks).length)}%</div></div>
        <div className="stat-card"><div>Next Fee Due</div><div>₹{due ? due.amount.toLocaleString() : 0}</div></div>
      </div>
    </>
  ));
}

function ViewChildAttendance({ state }) {
  return panelWrapper('View Attendance', 'Color-coded calendar interface tracking daily attendance presence records.', (
    <div className="table-card">
      <table>
        <thead><tr><th>Child</th><th>Attendance</th><th>Presence Rate</th></tr></thead>
        <tbody>{state.students.map(student => { const total = student.attendance.present + student.attendance.absent + student.attendance.late; return <tr key={student.admissionNumber}><td>{student.name}</td><td>{student.attendance.present}/{total}</td><td>{Math.round((student.attendance.present / total) * 100)}%</td></tr>; })}</tbody>
      </table>
    </div>
  ));
}

function ChatWithTeachers({ state }) {
  return panelWrapper('Chat with Teachers', 'Interactive conversation messenger module to connect with classroom instructors.', (
    <form className="grid-form" onSubmit={(event) => { event.preventDefault(); alert('Message sent to teacher.'); }}>
      <label>Teacher<select name="teacher">{state.teachers.map(teacher => <option key={teacher.employeeId} value={teacher.employeeId}>{teacher.name}</option>)}</select></label>
      <label>Message<textarea name="message" rows="4" required /></label>
      <div className="form-actions"><button type="submit">Send</button></div>
    </form>
  ));
}

function DownloadReportCards({ state }) {
  return panelWrapper('Download Report Cards', 'Access repository to view and download digitally compiled school report card documents.', (
    <div className="grid-cards">{state.students.map(student => <div key={student.admissionNumber} className="stat-card"><div>{student.name}</div><div>Grade {student.grade}{student.section}</div><button>Download</button></div>)}</div>
  ));
}

function FeeCollection({ state, setState }) {
  const handleProcess = (feeId, student) => {
    setState(prev => ({
      ...prev,
      financials: { ...prev.financials, fees: prev.financials.fees.map(item => item.id === feeId ? { ...item, status: 'Paid' } : item) },
      notifications: [{ id: Date.now(), message: '[Fee payment successful] Payment processed for ' + student + '.', channels: ['Accountant', 'Parent'], time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) }, ...prev.notifications]
    }));
  };

  return panelWrapper('Fee Collection', 'Main account portal filterable by class to track payments, process due fees, and generate receipts.', (
    <div className="table-card">
      <table>
        <thead><tr><th>Student</th><th>Fee</th><th>Amount</th><th>Due Date</th><th>Status</th><th>Action</th></tr></thead>
        <tbody>
          {state.financials.fees.map(fee => (
            <tr key={fee.id}>
              <td>{fee.student}</td>
              <td>{fee.type}</td>
              <td>₹{fee.amount.toLocaleString()}</td>
              <td>{fee.dueDate}</td>
              <td>{fee.status}</td>
              <td><button onClick={() => handleProcess(fee.id, fee.student)}>Process</button></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  ));
}

function SalaryManagement({ state }) {
  return panelWrapper('Salary Management', 'Operational sheet detailing staff payrolls, deductions, and automatic dispatch distributions.', (
    <div className="table-card">
      <table>
        <thead><tr><th>Employee</th><th>Name</th><th>Salary</th><th>Status</th><th>Action</th></tr></thead>
        <tbody>{state.teachers.map(teacher => <tr key={teacher.employeeId}><td>{teacher.employeeId}</td><td>{teacher.name}</td><td>₹{teacher.salary.toLocaleString()}</td><td>{teacher.leaveStatus === 'Approved' ? 'On Leave' : 'Active'}</td><td><button onClick={() => alert(`Salary dispatched for ${teacher.name}.`)}>Disburse</button></td></tr>)}</tbody>
      </table>
    </div>
  ));
}

function ExpenseTracking({ state, setState }) {
  return panelWrapper('Expense Tracking', 'Cost logger canvas capturing incoming utility expenses, bills, and vendor transaction items.', (
    <div className="table-card">
      <table>
        <thead><tr><th>ID</th><th>Category</th><th>Description</th><th>Amount</th><th>Date</th></tr></thead>
        <tbody>{state.financials.expenses.map(expense => <tr key={expense.id}><td>{expense.id}</td><td>{expense.category}</td><td>{expense.description}</td><td>₹{expense.amount.toLocaleString()}</td><td>{expense.date}</td></tr>)}</tbody>
      </table>
    </div>
  ));
}

function FinancialReports({ state }) {
  const revenue = state.financials.fees.reduce((sum, fee) => sum + fee.amount, 0);
  const expense = state.financials.expenses.reduce((sum, expense) => sum + expense.amount, 0);
  const profit = revenue - expense;
  return panelWrapper('Financial Reports', 'Summary engine packing generation metrics for accounting statement overviews.', (
    <div className="metrics-grid"><div className="metric-card"><div>Total Revenue</div><div>₹{revenue.toLocaleString()}</div></div><div className="metric-card"><div>Total Expenses</div><div>₹{expense.toLocaleString()}</div></div><div className="metric-card"><div>Net Balance</div><div>₹{profit.toLocaleString()}</div></div></div>
  ));
}

function TaxReports({ state }) {
  const totalExpenses = state.financials.expenses.reduce((sum, expense) => sum + expense.amount, 0);
  const taxLiability = Math.round(totalExpenses * 0.18);
  return panelWrapper('Tax Reports', 'Specialized computation panel exporting structured auditing sheets.', (
    <div className="grid-cards"><div className="stat-card"><div>Expense Total</div><div>₹{totalExpenses.toLocaleString()}</div></div><div className="stat-card"><div>Tax Liability</div><div>₹{taxLiability.toLocaleString()}</div></div></div>
  ));
}

export default App;
